      // On iOS, close picker after selection
      if (Platform.OS === 'ios') {
        setShowTimePicker(false);
      }
    } else if (type === 'dismissed') {
      console.log('Time picker dismissed without selection');
    }
  };

  const categoryPlaceholder = category || 'Select service category';

  return (
    <>
