          <TextInput
            style={[styles.input, { backgroundColor: inputBg, color: textColor, borderColor }]}
            placeholder="Enter gig address"
            placeholderTextColor={isDark ? '#888' : '#999'}
            value={address}
            onChangeText={setAddress}
