42: export default function FloatingTabBar({
43:   tabs,
44:   containerWidth = screenWidth / 2.5,
45:   borderRadius = 35,
46:   bottomMargin
47: }: FloatingTabBarProps) {
48:   const router = useRouter();
49:   const pathname = usePathname();
50:   const theme = useTheme();
51:   const animatedValue = useSharedValue(0);
52: 
53:   // Improved active tab detection with better path matching
54:   const activeTabIndex = React.useMemo(() => {
55:     // Find the best matching tab based on the current pathname
56:     let bestMatch = -1;
57:     let bestMatchScore = 0;
58: 
59:     tabs.forEach((tab, index) => {
60:       let score = 0;
61: 
62:       // Exact route match gets highest score
63:       if (pathname === tab.route) {
64:         score = 100;
65:       }
66:       // Check if pathname starts with tab route (for nested routes)
67:       else if (pathname.startsWith(tab.route as string)) {
68:         score = 80;
69:       }
70:       // Check if pathname contains the tab name
71:       else if (pathname.includes(tab.name)) {
72:         score = 60;
73:       }
74:       // Check for partial matches in the route
75:       else if (tab.route.includes('/(tabs)/') && pathname.includes(tab.route.split('/(tabs)/')[1])) {
76:         score = 40;
77:       }
78: 
79:       if (score > bestMatchScore) {
80:         bestMatchScore = score;
81:         bestMatch = index;
82:       }
83:     });
84: 
85:     // Default to first tab if no match found
86:     return bestMatch >= 0 ? bestMatch : 0;
87:   }, [pathname, tabs]);
88: 
89:   React.useEffect(() => {
90:     if (activeTabIndex >= 0) {
91:       animatedValue.value = withSpring(activeTabIndex, {
92:         damping: 20,
93:         stiffness: 120,
94:         mass: 1,
95:       });
96:     }
97:   }, [activeTabIndex, animatedValue]);
98: 
