107:    return {
108:      transform: [
109:        {
110:          translateX: interpolate(
111:            animatedValue.value,
112:            [0, tabs.length - 1],
113:            [0, tabWidth * (tabs.length - 1)]
114:          ),
115:        },
116:      ],
